import zeep
from zeep import Client
from zeep.plugins import HistoryPlugin
from lxml import etree
import re


def sanitize_input(user_input):
    if user_input is None:
        return ""
    
    user_input = str(user_input)
    
    user_input = re.sub(r'[<>&"\']', '', user_input)
    
    user_input = user_input.replace('--', '')
    user_input = user_input.replace('/*', '')
    user_input = user_input.replace('*/', '')
    
    user_input = re.sub(r'[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]', '', user_input)
    
    return user_input.strip()


def validate_policy_number(policy_number):
    sanitized = sanitize_input(policy_number)
    
    if not re.match(r'^[A-Z0-9\-]{5,20}$', sanitized):
        raise ValueError("Invalid policy number format")
    
    return sanitized


def validate_customer_name(customer_name):
    sanitized = sanitize_input(customer_name)
    
    if not re.match(r'^[a-zA-Z\s\-\.]{2,100}$', sanitized):
        raise ValueError("Invalid customer name format")
    
    return sanitized


class InsuranceSOAPClient:
    def __init__(self, wsdl_url):
        self.history = HistoryPlugin()
        self.client = Client(wsdl_url, plugins=[self.history])
        
    def lookup_policy(self, policy_number, customer_name):
        validated_policy_number = validate_policy_number(policy_number)
        validated_customer_name = validate_customer_name(customer_name)
        
        try:
            response = self.client.service.PolicyLookup(
                PolicyNumber=validated_policy_number,
                CustomerName=validated_customer_name
            )
            return response
        except Exception as e:
            print(f"Error during SOAP request: {e}")
            raise
    
    def get_insurance_quote(self, policy_number, customer_name):
        validated_policy_number = validate_policy_number(policy_number)
        validated_customer_name = validate_customer_name(customer_name)
        
        try:
            response = self.client.service.GetQuote(
                PolicyNumber=validated_policy_number,
                CustomerName=validated_customer_name
            )
            return response
        except Exception as e:
            print(f"Error during SOAP request: {e}")
            raise


def main():
    wsdl_url = "http://example-insurance-service.com/service?wsdl"
    
    print("Insurance Policy Lookup System")
    print("-" * 40)
    
    policy_number = input("Enter policy number: ")
    customer_name = input("Enter customer name: ")
    
    try:
        client = InsuranceSOAPClient(wsdl_url)
        
        print("\nLooking up policy...")
        result = client.lookup_policy(policy_number, customer_name)
        
        print("\nPolicy Lookup Result:")
        print(result)
        
        print("\nGetting insurance quote...")
        quote = client.get_insurance_quote(policy_number, customer_name)
        
        print("\nInsurance Quote:")
        print(quote)
        
    except ValueError as ve:
        print(f"\nValidation Error: {ve}")
    except Exception as e:
        print(f"\nError: {e}")


if __name__ == "__main__":
    main()